--
-- Create view "EMPLOYEES_VU"
--
CREATE VIEW EMPLOYEES_VU (
  EMPLOYEE_ID,
  EMPLOYEES,
  DEPARTMENT_ID
) AS
    SELECT EMPLOYEE_ID,
           FIRST_NAME || ' ' || LAST_NAME AS EMPLOYEES,
           DEPARTMENT_ID
      FROM EMPLOYEES;

--
-- Create view "EMP_VIEW"
